import{CODE_MODE_TOOL_NAME,WORKFLOW_TOOL_NAME}from"#shared/code-mode.js";import{workflowToolDescription}from"#harness/workflow-tool-description.js";const WORKFLOW_SURFACE={toolName:WORKFLOW_TOOL_NAME,claims:e=>e?.runtimeAction!==void 0,describe:({generated:e,toolNames:t})=>{let n=workflowToolDescription(t);return e.length>0?`${n}\n\n${e}`:n}},CODE_MODE_SURFACE={toolName:CODE_MODE_TOOL_NAME,claims:(e,t)=>e?.runtimeAction!==void 0||t.execute!==void 0};function selectSandboxSurfaces(e){let t=[];return e.workflow===!0&&t.push(WORKFLOW_SURFACE),e.codeMode===!0&&t.push(CODE_MODE_SURFACE),t}function isSandboxEnabled(e){return e.codeMode===!0||e.workflow===!0}const ALL_SANDBOX_SURFACES=[WORKFLOW_SURFACE,CODE_MODE_SURFACE];export{ALL_SANDBOX_SURFACES,CODE_MODE_SURFACE,WORKFLOW_SURFACE,isSandboxEnabled,selectSandboxSurfaces};